+export interface DurationHistoryEntry {
+  duration?: number
+  recordedAt?: number
+  observations?: DurationObservation[]
+}
+export type DurationHistory = Record<string, DurationHistoryEntry>
+
+function validObservation(value: unknown): value is DurationObservation {
+  return !!value && typeof value === 'object' && Number.isFinite((value as DurationObservation).duration) && Number.isFinite((value as DurationObservation).recordedAt)
+}
+
+export function normalizeDurationHistory(value: unknown): DurationHistory | null {
+  if (!value || typeof value !== 'object' || Array.isArray(value)) return null
+  const history: DurationHistory = {}
+  for (const [path, entry] of Object.entries(value)) {
+    if (typeof entry === 'number' && Number.isFinite(entry)) history[slash(path)] = { duration: entry, recordedAt: 0 }
+    else if (entry && typeof entry === 'object') {
+      const item = entry as DurationHistoryEntry
+      if (validObservation(item)) history[slash(path)] = { duration: item.duration, recordedAt: item.recordedAt }
+      else if (Array.isArray(item.observations) && item.observations.every(validObservation)) history[slash(path)] = { observations: item.observations }
+    }
+  }
+  return history
+}
+
+export async function readDurationHistory(root: string, path: string): Promise<DurationHistory | null> {
+  try {
+    return normalizeDurationHistory(JSON.parse(await fs.readFile(resolve(root, path), 'utf8')))
+  }
+  catch {
+    return null
+  }
+}
+
+export function getObservations(entry: DurationHistoryEntry | undefined, ttl: number, now = Date.now()): DurationObservation[] {
+  const observations = entry?.observations ?? (validObservation(entry) ? [{ duration: entry.duration, recordedAt: entry.recordedAt }] : [])
+  const cutoff = now - ttl
+  return ttl > 0 ? observations.filter(item => item.recordedAt === 0 || item.recordedAt >= cutoff) : observations
+}
+
+export function getDuration(history: DurationHistory, file: string, ttl: number, smoothing: DurationSmoothing): number | undefined {
+  const observations = getObservations(history[slash(file)], ttl)
+  return observations.length ? smoothDurations(observations, smoothing) : undefined
+}
+
+export async function writeDurationHistory(root: string, path: string, durations: Record<string, number>, ttl: number, maxRuns: number): Promise<void> {
+  const existing = await readDurationHistory(root, path) ?? {}
